   841→        let paragraph = Paragraph::new(lines);
   842→        paragraph.render(area, buf);
   843→    }
   844→
   845→    /// Render worker cost breakdown.
   846→    fn render_worker_costs(&self, area: Rect, buf: &mut Buffer) {
   847→        if self.data.worker_costs.is_empty() {
   848→            let msg = Paragraph::new("No worker data").style(Style::default().fg(Color::Gray));
   849→            msg.render(area, buf);
   850→            return;
   851→        }
   852→
   853→        // Find max cost for scaling bars
   854→        let max_cost = self
   855→            .data
   856→            .worker_costs
   857→            .iter()
   858→            .map(|w| w.total_cost_usd)
   859→            .fold(0.0_f64, f64::max);
   860→
   861→        let mut lines = Vec::new();
   862→
   863→        // Session total
   864→        if self.data.session_total > 0.0 {
   865→            lines.push(Line::from(vec![
   866→                Span::styled("Session: ", Style::default().fg(Color::Gray)),
   867→                Span::styled(
   868→                    format_usd(self.data.session_total),
   869→                    Style::default()
   870→                        .fg(Color::Cyan)
   871→                        .add_modifier(Modifier::BOLD),
   872→                ),
   873→            ]));
   874→            lines.push(Line::from(""));
   875→        }
   876→
   877→        // Header
   878→        lines.push(Line::from(vec![
   879→            Span::styled("Worker", Style::default().fg(Color::Gray)),
   880→            Span::raw("  "),
   881→            Span::styled("#", Style::default().fg(Color::Gray)),
   882→            Span::raw(" "),
   883→            Span::styled("Cost", Style::default().fg(Color::Gray)),
   884→            Span::raw("    "),
   885→            Span::styled("Task", Style::default().fg(Color::Gray)),
   886→        ]));
   887→
   888→        // Show top workers (limit to fit area)
   889→        let worker_limit = (area.height.saturating_sub(4) as usize).min(8);
   890→        for worker in self.data.worker_costs.iter().take(worker_limit) {
   891→            // Truncate worker ID
   892→            let worker_id = if worker.worker_id.len() > 12 {
   893→                format!("{}…", &worker.worker_id[..11])
   894→            } else {
   895→                worker.worker_id.clone()
   896→            };
   897→
   898→            // Color based on expense
   899→            let cost_color = if worker.is_expensive {
   900→                Color::LightRed
   901→            } else if worker.total_cost_usd > max_cost * 0.5 {
   902→                Color::Yellow
   903→            } else {
   904→                Color::Green
   905→            };
   906→
   907→            // Expense indicator
   908→            let indicator = if worker.is_expensive { "⚠ " } else { "  " };
   909→
   910→            // Task info
   911→            let task = worker
   912→                .bead_id
   913→                .as_ref()
   914→                .map(|t| {
   915→                    if t.len() > 10 {
   916→                        format!("{}…", &t[..9])
   917→                    } else {
   918→                        t.clone()
   919→                    }
   920→                })
   921→                .unwrap_or_else(|| "-".to_string());
   922→
   923→            lines.push(Line::from(vec![
   924→                Span::styled(indicator, Style::default().fg(Color::LightRed)),
   925→                Span::styled(
   926→                    format!("{:<12}", worker_id),
   927→                    Style::default().fg(Color::White),
   928→                ),
   929→                Span::raw(" "),
   930→                Span::styled(
   931→                    format!("{:>2}", worker.call_count.min(99)),
   932→                    Style::default().fg(Color::Gray),
   933→                ),
   934→                Span::raw(" "),
   935→                Span::styled(format_usd(worker.total_cost_usd), Style::default().fg(cost_color)),
   936→                Span::raw("  "),
   937→                Span::styled(task, Style::default().fg(Color::DarkGray)),
   938→            ]));
   939→        }
   940→
   941→        // Summary line
   942→        let expensive_count = self.data.expensive_worker_count();
   943→        if expensive_count > 0 {
   944→            lines.push(Line::from(""));
   945→            lines.push(Line::from(vec![
   946→                Span::styled(
   947→                    format!("⚠ {} expensive", expensive_count),
   948→                    Style::default().fg(Color::LightRed),
   949→                ),
   950→                Span::raw(" (≥"),
   951→                Span::styled(
   952→                    format_usd(self.data.expensive_threshold),
   953→                    Style::default().fg(Color::Gray),
   954→                ),
   955→                Span::raw(")"),
   956→            ]));
   957→        }
   958→
   959→        let paragraph = Paragraph::new(lines);
   960→        paragraph.render(area, buf);
   961→    }
   962→}
